#include <vector>
#include "hardtanh_custom_tiling.h"
#include "register/op_def_registry.h"

// Optional platform info if needed
#include "tiling/platform/platform_ascendc.h"

namespace {

// UB model for this kernel:
//   inQueueX: 2 * tile
//   outQueueY: 2 * tile
//   midQueue: 1 * tile
//   clampTmp: clampTmpSize (single shared buffer reused by both ClampMin and ClampMax)
// Total UB bytes = 5 * tile * sizeof(float) + clampTmpSize
static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;  // conservative per-core share
static constexpr uint32_t ALIGN_ELEMS = 2048;            // favor larger DMA bursts
static constexpr uint32_t HARD_CAP_ELEMS = 32768;        // avoid too-large per-iter latency

static inline uint32_t AlignDown(uint32_t x, uint32_t a)
{
    return (a == 0u) ? x : (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b)
{
    return (b == 0u) ? 0u : (a + b - 1u) / b;
}

} // anonymous

namespace optiling {

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    HardtanhCustomTilingData tiling;

    const gert::Shape* inShape = context->GetInputShape(0);
    const uint32_t totalLength =
        static_cast<uint32_t>(inShape->GetOriginShape().GetShapeSize());

    // HardTanh range constants
    constexpr float kMinVal = -1.0f;
    constexpr float kMaxVal =  1.0f;

    // Query Clamp temporary buffer size range on host for float input
    uint32_t clampMaxValue = 0;
    uint32_t clampMinValue = 0;
    // Build a 1-D shape [totalLength] for this elementwise op
    std::vector<int64_t> shape_vec = {static_cast<int64_t>(totalLength)};
    ge::Shape geShape(shape_vec);
    AscendC::GetClampMaxMinTmpSize(geShape, /*typeSize=*/4, /*isReuseSource=*/false,
                                   clampMaxValue, clampMinValue);

    // Choose a safe temporary size within [min, max]. Prefer min to save UB.
    uint32_t clampTmpSize = clampMinValue;

    // Compute tile length from UB budget after reserving clampTmpSize
    uint32_t availBytes = (UB_BUDGET_BYTES > clampTmpSize) ? (UB_BUDGET_BYTES - clampTmpSize) : 0u;
    // Each tile needs 5 * tile * sizeof(float) bytes
    uint32_t bytesPerElem = 5u * sizeof(float);
    uint32_t maxTileElems = (bytesPerElem > 0) ? (availBytes / bytesPerElem) : 0u;

    maxTileElems = AlignDown(maxTileElems, ALIGN_ELEMS);
    if (maxTileElems < ALIGN_ELEMS) maxTileElems = ALIGN_ELEMS;
    if (maxTileElems > HARD_CAP_ELEMS) maxTileElems = AlignDown(HARD_CAP_ELEMS, ALIGN_ELEMS);

    uint32_t tileLen = maxTileElems;
    if (totalLength < tileLen) {
        const uint32_t aligned = AlignDown(totalLength, ALIGN_ELEMS);
        tileLen = (aligned > 0) ? aligned : totalLength;
    }

    // Adaptive blockDim
    const uint32_t numTiles = (tileLen == 0) ? 1u : CeilDiv(totalLength, tileLen);
    uint32_t blockDim = numTiles;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;

    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalLength);
    tiling.set_tileLength(tileLen);
    tiling.set_blockDim(blockDim);
    tiling.set_clampTmpSize(clampTmpSize);
    tiling.set_minVal(kMinVal);
    tiling.set_maxVal(kMaxVal);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

namespace ge {

